    params = [p.strip() for p in method_sig.split(",") if p.strip()]
    if params[:1] and any("neighbor" in p or "neighbors" in p or "near" in p for p in params):
        # update(neighbors, dt, width, height) or update(neighbors, width, height, dt)
        if any("dt" in p for p in params):
            # put dt after neighbors if dt present
            boid_update_call = "boid.update(neighbors, dt, width, height)"
        else:
            boid_update_call = "boid.update(neighbors, width, height, dt)"
    elif any("dt" in p for p in params):
        # likely update(dt, width, height)
        boid_update_call = "boid.update(dt, width, height)"
    else:
        # fallback: pass neighbors then dt,width,height
        boid_update_call = "boid.update(neighbors, dt, width, height)"
else:
    # no explicit signature found; default to neighbors, dt, width, height
    boid_update_call = "boid.update(neighbors, dt, width, height)"

# Construct flock.js source following CONTRACT
flock_js = f"""// flock.js
// Implements Flock per CONTRACT
import {{ Boid }} from "./boid.js";
import {{ SpatialHash }} from "./utils.js";

export class Flock {{
  constructor(count = 100, width = 800, height = 600) {{
    this.boids = [];
    this.grid = new SpatialHash(64); // cell size; tuned for typical perception
    this._w = width;
    this._h = height;
    for (let i = 0; i < count; i++) {{
      // Randomize initial positions inside given dimensions
      const x = Math.random() * width;
      const y = Math.random() * height;
      // Let Boid constructor decide defaults; try common signatures:
      // new Boid(x, y, vx, vy, color) or new Boid(x,y)
      // Provide x,y and a small random velocity and color if Boid supports it.
      const angle = Math.random() * Math.PI * 2;
      const speed = Math.random() * 50;
      const vx = Math.cos(angle) * speed;
      const vy = Math.sin(angle) * speed;
      // vivid color: random hue
      const hue = Math.floor(Math.random() * 360);
      const color = `hsl(${hue} 80% 60%)`;
      let b;
      try {{
        // try multiple constructor shapes
        b = new Boid(x, y, vx, vy, color);
      }} catch (e) {{
        try {{
          b = new Boid(x, y, color);
          // if it didn't accept velocity, try to set it directly
          if (typeof b.vx !== "undefined") {{
            b.vx = vx; b.vy = vy;
          }}
        }} catch (e2) {{
          // last resort: call with only position
          b = new Boid(x, y);
          if (typeof b.vx !== "undefined") {{ b.vx = vx; b.vy = vy; }}
          if (typeof b.color !== "undefined") {{ b.color = color; }}
        }}
      }}
      this.boids.push(b);
    }}
  }}

  // Replace grid each frame and update boids using neighbors from the grid.
  update(width, height, dt) {{
    this._w = width;
    this._h = height;
    // rebuild spatial hash
    this.grid.clear();
    for (const b of this.boids) {{
      // assume boid has x and y properties
      this.grid.insert(b);
    }}

    // For each boid, query neighbors and call its update.
    for (const b of this.boids) {{
      // Determine a reasonable query radius: prefer boid.perception if present
      let r = 60;
      if (typeof b.perception !== "undefined" && b.perception > 0) r = b.perception;
      // If boid has separate separation radius, use the larger for neighbor listing
      if (typeof b.separationRadius !== "undefined") {{
        r = Math.max(r, b.separationRadius);
      }}
      const neighbors = this.grid.query(b.x, b.y, r) || [];
      // The SpatialHash may return the item itself; filter it out
      const others = neighbors.filter(item => item !== b);
      // Call boid.update with discovered signature
      try {{
        // Use the preferred call discovered at inspection time
        {boid_update_call};
      }} catch (e) {{
        // Fallback attempts with different argument orders
        try {{ b.update(others, width, height, dt); }} catch (e2) {{
          try {{ b.update(dt, width, height); }} catch (e3) {{
            // last resort: call update() with no args
            try {{ b.update(); }} catch (e4) {{ /* ignore */ }}
          }}
        }}
      }}
      // Ensure wrapping position if Boid didn't handle edges
      if (typeof b.x === "number" && typeof b.y === "number") {{
        if (b.x < 0) b.x += width;
        if (b.x >= width) b.x -= width;
        if (b.y < 0) b.y += height;
        if (b.y >= height) b.y -= height;
      }}
    }}
  }}

  draw(ctx) {{
    for (const b of this.boids) {{
      try {{
        if (typeof b.draw === "function") {{
          b.draw(ctx);
        }} else {{
          // fallback: draw a small circle
          ctx.save();
          ctx.fillStyle = b.color || "white";
          ctx.beginPath();
          ctx.arc(b.x, b.y, 2, 0, Math.PI * 2);
          ctx.fill();
          ctx.restore();
        }}
      }} catch (e) {{
        // ignore drawing errors per-boid
      }}
    }}
  }}
}}
"""

# Write the file
write_file("output/boids-simulation/flock.js", flock_js)

# Return only 'ok' as required
done("ok")
